
import React from 'react';//надо вставить дополнительно
import Card from './Card.jsx';
import SubCards from './SubCards.jsx';

window.props = [];


const Cards = (props) => { 
    if(props.props.sites){
        if(props.props.sites.length) {
            return (<SubCards props={props.props} key = {props.id} onClose={props.onClose}/>)
        } 
    } else {
        return (<Card props={props.props} key = {props.id}/>)
    }
}


const Catalog = (props) => {
    // let messageElement = props.data.map( p =>  <GetImgCatalog key = {p.urlSite + p.id} url = {p.urlSite} img = {p.img} id = {p.id}/>);
    return (
        <>
            {
                props.data.map(p => 
                    <article key = {p.id} className="card catalog__item" data-i = {p.id}>
                        <Cards key = {p.urlSite + p.id} props = {p}/>
                    </article>
                )
            }
        </>
    )
}

const Content = (props) => {
    let reversed = [...props.data].reverse();
    // console.log(reversed);
    return (
        <main className="catalog page__catalog">
            <Catalog key={new Date().valueOf()} data = {reversed}/>
        </main>
    )
}


export default Content;

