
import React, { useState } from 'react';//надо вставить дополнительно

window.props = [];

const CardItem = ({props}) => { 
    return (
        <div className="card-item">
            <a href={props.urlSite} className="text-color-heavenly" target="_blank" rel="noreferrer"> 
                <div className="selector selector-simple" style={{background: 'url(' + props.img + ') center center'}}/>
            </a>
            <div className="card__description">
                <h3 className="card__title">{props.title}</h3>
                <a className="card__url" href = {props.urlGithub} target="_blank" rel="noreferrer"> 
                    <span style={{color: 'black'}}> GitHub: </span> {props.urlGithub}
                </a>
                <div>
                    <p className="card__info">Сборка на {props.info} </p>
                    <span className = "bottom">
                        <img alt="Логотип программы " src={props.urlLogo} height="25" className = "bottom"/>
                    </span>
                </div>
            </div>
        </div>
    )

}

const CardItems = ({props, mode}) => { 
    return (
        <>
            {mode &&
                <div className="card-items zoomIn">
                    <div className="background-white">
                        {props.map(p => <CardItem key = {p.id} props = {p}/>)}
                    </div>
                </div>
            }
            {!mode &&
                <div className="card-items zoomOut">
                    <div className="background-white">
                        {props.map(p => <CardItem key = {p.id} props = {p}/>)}
                    </div>
                </div>
            }
        </>
    )

}

const SubCards = ({props}) => { 
    const[modal, setModal] = useState(true);
    return (
        <>
            {modal &&
                <> 
                    <div onClick = {() =>setModal(false)}>
                        <div className="selector selector-simple" style={{background: 'url(' + props.img + ') center center'}}/>
                    </div>
                    <div className="card__description">
                        <h3 className="card__title">{props.title}</h3>
                        <a className="card__url" href = {props.urlGithub} target="_blank" rel="noreferrer"> 
                            <span style={{color: 'black'}}> GitHub: </span> {props.urlGithub}
                        </a>
                    </div>
                    <div>
                        <p className="card__info">Сборка на {props.info} </p>
                        <span className = "bottom">
                            <img alt="Логотип программы " src={props.urlLogo} height="25" className = "bottom"/>
                        </span>
                    </div>
                    {/* <CardItems props={props.sites} mode={false}/> */}
                </>
            }
            {!modal &&
                <> 
                    <div className="background-grey" onClick = {() => setModal(true)}></div>
                        <div className="selector selector-simple " style={{background: 'url(' + props.img + ') center center'}}/>
                    <div className="card__description">
                        <h3 className="card__title">{props.title}</h3>
                    </div>
                        <CardItems props={props.sites} mode={true}/>
                </>
            }

        </>
        
    ) 
}


export default SubCards;

