
import React from 'react';//надо вставить дополнительно

window.props = [];


const Card = ({props}) => { 
    return (
        <>
            <a href={props.urlSite} target="_blank" rel="noreferrer">
                {props.id >= 26 && props.id < 31 && 
                    <div className="selector-ripples selector" style={{background: 'url(' + props.img + ') center center'}}/>
                } 
                {props.id < 26 && <div className="selector" style={{background: 'url(' + props.img + ') center center'}}/>
                } 
            </a>
            <div className="card__description">
                <h3 className="card__title">{props.title}</h3>
                <a className="card__url" href = {props.urlGithub} target="_blank" rel="noreferrer"> 
                    <span style={{color: 'black'}}> GitHub: </span> {props.urlGithub}
                </a>
                <div>
                    <p className="card__info">Сборка на {props.info} </p>
                    <span className = "bottom">
                        <img alt="Логотип программы " src={props.urlLogo} height="25" className = "bottom"/>
                    </span>
                </div>
            </div>
        </>
        
    ) 
}


export default Card;

